// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('select box department', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('select box department', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    await driver.sleep(3000);
    assert(await driver.findElement(By.css(".ant-select-selection-item")).getText() == "すべて");
    await driver.findElement(By.css(".ant-select-selection-item")).click();
    await driver.findElement(By.xpath("//div[6]")).click();
    assert(await driver.findElement(By.css(".ant-select-selection-item")).getText() == "00075 : ｾｶﾝﾄﾞｽﾄﾘｰﾄ事業部");
  });
});
